import{_ as s,o as n,c as t,ag as i}from"./chunks/framework.Cqf6AMW8.js";const k=JSON.parse('{"title":"JavaScript 异步编程","description":"JavaScript 异步编程相关知识，包括单线程特性、同步与异步、执行机制等。","frontmatter":{"title":"JavaScript 异步编程","description":"JavaScript 异步编程相关知识，包括单线程特性、同步与异步、执行机制等。","date":"2026-04-21T00:00:00.000Z","tags":["JavaScript","异步编程","事件循环"],"sidebar":"auto"},"headers":[],"relativePath":"docs/frontend/javascript/JS-DOM-3-js异步.md","filePath":"docs/frontend/javascript/JS-DOM-3-js异步.md","lastUpdated":1776715536000}'),e={name:"docs/frontend/javascript/JS-DOM-3-js异步.md"};function p(l,a,d,h,r,o){return n(),t("div",null,[...a[0]||(a[0]=[i(`<p>#JavaScript</p><p>======================================================</p><h2 id="_1-单线程特性" tabindex="-1">1. 单线程特性 <a class="header-anchor" href="#_1-单线程特性" aria-label="Permalink to &quot;1. 单线程特性&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td>定义</td><td>JavaScript 语言的一大特点就是单线程，也就是说，同一个时间只能做一件事</td></tr><tr><td>原因</td><td>JavaScript 是为处理页面中用户的交互，以及操作 DOM 而诞生的。比如对某个 DOM 元素进行添加和删除操作，不能同时进行，应该先进行添加，之后再删除</td></tr><tr><td>问题</td><td>单线程意味着所有任务需要排队，前一个任务结束，才会执行后一个任务。如果 JS 执行的时间过长，会造成页面的渲染不连贯，导致页面渲染加载阻塞的感觉</td></tr><tr><td>解决方案</td><td>利用多核 CPU 的计算能力，HTML5 提出 Web Worker 标准，允许 JavaScript 脚本创建多个线程</td></tr></tbody></table><p>======================================================</p><h2 id="_2-同步与异步及任务类型" tabindex="-1">2. 同步与异步及任务类型 <a class="header-anchor" href="#_2-同步与异步及任务类型" aria-label="Permalink to &quot;2. 同步与异步及任务类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>定义</th><th>示例</th></tr></thead><tbody><tr><td>同步</td><td>前一个任务结束后再执行后一个任务，程序的执行顺序与任务的排列顺序是一致的、同步的</td><td>做饭的同步做法：先烧水煮饭，等水开了（10分钟之后），再去切菜、炒菜</td></tr><tr><td>异步</td><td>在做一件事情时，因为这件事情会花费很长时间，在做这件事的同时，还可以去处理其他事情</td><td>做饭的异步做法：在烧水的同时，利用这10分钟去切菜、炒菜</td></tr></tbody></table><h3 id="任务类型结构" tabindex="-1">任务类型结构 <a class="header-anchor" href="#任务类型结构" aria-label="Permalink to &quot;任务类型结构&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>任务类型</span></span>
<span class="line"><span>├── 同步任务</span></span>
<span class="line"><span>│   ├── 执行方式：在主线程上执行</span></span>
<span class="line"><span>│   └── 特点：形成一个执行栈</span></span>
<span class="line"><span>└── 异步任务</span></span>
<span class="line"><span>    ├── 执行方式：通过回调函数实现</span></span>
<span class="line"><span>    ├── 特点：相关添加到任务队列中（任务队列也称为消息队列）</span></span>
<span class="line"><span>    └── 类型：</span></span>
<span class="line"><span>        ├── 普通事件：click、resize 等</span></span>
<span class="line"><span>        ├── 资源加载：load、error 等</span></span>
<span class="line"><span>        └── 定时器：setInterval、setTimeout 等</span></span></code></pre></div><p>======================================================</p><h2 id="_3-执行机制" tabindex="-1">3. 执行机制 <a class="header-anchor" href="#_3-执行机制" aria-label="Permalink to &quot;3. 执行机制&quot;">​</a></h2><h3 id="_3-1-执行流程" tabindex="-1">3.1 执行流程 <a class="header-anchor" href="#_3-1-执行流程" aria-label="Permalink to &quot;3.1 执行流程&quot;">​</a></h3><ol><li>先执行执行栈中的同步任务</li><li>异步任务放入任务队列中</li><li>一旦执行栈中的所有同步任务执行完毕，系统就会按次序读取任务队列中的异步任务，于是被读取的异步任务结束等待状态，进入执行栈，开始执行</li></ol><h3 id="_3-2-事件循环" tabindex="-1">3.2 事件循环 <a class="header-anchor" href="#_3-2-事件循环" aria-label="Permalink to &quot;3.2 事件循环&quot;">​</a></h3><p>由于主线程不断的重复获得任务、执行任务、再获得任务、再执行，所以这种机制被称为事件循环（event loop）。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>JS 执行机制</span></span>
<span class="line"><span>├── 开始</span></span>
<span class="line"><span>│   └── 执行栈</span></span>
<span class="line"><span>│       ├── 主线程执行完毕，读取任务队列</span></span>
<span class="line"><span>│       └── 重复执行</span></span>
<span class="line"><span>├── 任务队列（消息队列）</span></span>
<span class="line"><span>│   ├── 任务队列1: onload、onclick 等</span></span>
<span class="line"><span>│   ├── 任务队列2: setTimeout、setInterval 等</span></span>
<span class="line"><span>│   └── 任务队列3: 网络请求等</span></span>
<span class="line"><span>└── Web API（异步处理）</span></span>
<span class="line"><span>    ├── ajax（网络请求）</span></span>
<span class="line"><span>    ├── DOM事件（DOM 操作）</span></span>
<span class="line"><span>    └── timer（定时器）</span></span></code></pre></div><p>======================================================</p><h2 id="_4-执行栈与任务队列" tabindex="-1">4. 执行栈与任务队列 <a class="header-anchor" href="#_4-执行栈与任务队列" aria-label="Permalink to &quot;4. 执行栈与任务队列&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>描述</th><th>示例</th></tr></thead><tbody><tr><td>执行栈</td><td>同步任务执行的地方，按照顺序执行</td><td>console.log(1); console.log(2);</td></tr><tr><td>任务队列</td><td>异步任务等待执行的地方，按照顺序排队</td><td>setTimeout(fn, 0);</td></tr></tbody></table><h3 id="_4-1-示例分析" tabindex="-1">4.1 示例分析 <a class="header-anchor" href="#_4-1-示例分析" aria-label="Permalink to &quot;4.1 示例分析&quot;">​</a></h3><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">console.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">log</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">setTimeout</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">function</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    console.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">log</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">console.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">log</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>执行顺序：</p><ol><li>执行 <code>console.log(1)</code>（同步任务）</li><li>执行 <code>setTimeout</code>（异步任务），将回调函数放入任务队列</li><li>执行 <code>console.log(3)</code>（同步任务）</li><li>执行栈为空，从任务队列中取出回调函数，执行 <code>console.log(2)</code></li></ol><p>输出结果：1, 3, 2</p><p>======================================================</p>`,25)])])}const E=s(e,[["render",p]]);export{k as __pageData,E as default};
